    calculateNextRun(schedule) {
        const now = new Date();
        const [hours, minutes] = schedule.time.split(':').map(Number);
        
        let nextRun = new Date(now);
        nextRun.setHours(hours, minutes, 0, 0);
        
        // If the time has passed today, schedule for next occurrence
        if (nextRun <= now) {
            switch (schedule.frequency) {
                case 'daily':
                    nextRun.setDate(nextRun.getDate() + 1);
                    break;
                case 'weekly':
                    nextRun.setDate(nextRun.getDate() + 7);
                    break;
                case 'monthly':
                    nextRun.setMonth(nextRun.getMonth() + 1);
                    break;
            }
        }
        
        return nextRun;
    }

    getIntervalMs(frequency) {
        switch (frequency) {
            case 'daily':
                return 24 * 60 * 60 * 1000; // 24 hours
            case 'weekly':
                return 7 * 24 * 60 * 60 * 1000; // 7 days
            case 'monthly':
                return 30 * 24 * 60 * 60 * 1000; // 30 days
            default:
                return 24 * 60 * 60 * 1000;
        }
    }

    shouldRunNow(schedule) {
        const now = new Date();
        const [hours, minutes] = schedule.time.split(':').map(Number);
        
        // Check if current time matches schedule time (within 1 minute window)
        const currentTime = now.getHours() * 60 + now.getMinutes();
        const scheduledTime = hours * 60 + minutes;
        
        const timeMatches = Math.abs(currentTime - scheduledTime) <= 1;
        
        // Check day of week for weekly schedules
        let dayMatches = true;
        if (schedule.frequency === 'weekly' && schedule.days.length > 0) {
            const currentDay = now.toLocaleLowerCase().substring(0, 3);
            dayMatches = schedule.days.includes(currentDay);
        }
        
        // Check day of month for monthly schedules
        let dayOfMonthMatches = true;
        if (schedule.frequency === 'monthly' && schedule.days.length > 0) {
            dayOfMonthMatches = schedule.days.includes(now.getDate().toString());
        }
        
        return timeMatches && dayMatches && dayOfMonthMatches;
    }

